import React, { useEffect, useState } from "react";
import axios from "axios";

export default function VentasHistorial() {
  const [ventas, setVentas] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    obtenerHistorial();
  }, []);

  const obtenerHistorial = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/ventas");
      setVentas(res.data);
      setLoading(false);
    } catch (err) {
      console.error("Error al obtener historial de ventas:", err);
      setLoading(false);
    }
  };

  return (
    <div className="container mt-5">
      <h2 className="fw-bold mb-4">📜 Historial de Ventas</h2>

      {loading ? (
        <div className="alert alert-info text-center">Cargando ventas...</div>
      ) : ventas.length === 0 ? (
        <div className="alert alert-warning text-center">No hay ventas registradas.</div>
      ) : (
        <div className="table-responsive">
          <table className="table table-bordered table-hover shadow">
            <thead className="table-dark">
              <tr>
                <th>#</th>
                <th>Cliente</th>
                <th>Fecha</th>
                <th>Subtotal</th>
                <th>IVA</th>
                <th>Total</th>
                <th>Productos</th>
              </tr>
            </thead>
            <tbody>
              {ventas.map((venta, index) => (
                <tr key={index}>
                  <td>{venta.NumeroSecuencia}</td>
                  <td>{venta.Cliente?.Nombre || venta.ClienteID}</td>
                  <td>{new Date(venta.Fecha).toLocaleString()}</td>
                  <td>${venta.Subtotal.toFixed(2)}</td>
                  <td>${venta.IVA.toFixed(2)}</td>
                  <td className="fw-bold">${venta.Total.toFixed(2)}</td>
                  <td>
                    <details>
                      <summary className="text-primary" style={{ cursor: "pointer" }}>
                        Ver productos
                      </summary>

                      <table className="table table-sm mt-2">
                        <thead>
                          <tr>
                            <th>Producto</th>
                            <th>Cantidad</th>
                            <th>Precio</th>
                            <th>Subtotal</th>
                          </tr>
                        </thead>
                        <tbody>
                          {venta.productos.map((p, i) => (
                            <tr key={i}>
                              <td>{p.NombreProducto || p.ProductID}</td>
                              <td>{p.Cantidad}</td>
                              <td>${p.PrecioUnitario.toFixed(2)}</td>
                              <td>${(p.Cantidad * p.PrecioUnitario).toFixed(2)}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </details>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
